     1→/*
     2→ * acos() test harness — prints (input_hex, output_hex) pairs.
     3→ *
     4→ * Build two versions:
     5→ *   1. Linked with optimized Andes assembly acos  (test_acos_opt.elf)
     6→ *   2. Linked with toolchain's default acos       (test_acos_ref.elf)
     7→ * Run both, diff the output to find discrepancies.
     8→ */
     9→
    10→#include <math.h>
    11→#include <stdint.h>
    12→#include <stdio.h>
    13→#include <float.h>
    14→
    15→static inline uint64_t d2u(double d)
    16→{
    17→    union { double d; uint64_t u; } x;
    18→    x.d = d;
    19→    return x.u;
    20→}
    21→
    22→static inline double u2d(uint64_t u)
    23→{
    24→    union { double d; uint64_t u; } x;
    25→    x.u = u;
    26→    return x.d;
    27→}
    28→
    29→static void emit(double x)
    30→{
    31→    double r = acos(x);
    32→    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
    33→}
    34→
    35→static void emit_u(uint64_t bits)
    36→{
    37→    emit(u2d(bits));
    38→}
    39→
    40→/* ------------------------------------------------------------------ */
    41→/* Test points                                                         */
    42→/* ------------------------------------------------------------------ */
    43→
    44→/* 1. Special values */
    45→static void test_special(void)
    46→{
    47→    /* Zeros */
    48→    emit(0.0);
    49→    emit(-0.0);
    50→
    51→    /* NaN */
    52→    emit_u(0x7ff8000000000000ULL); /* qNaN */
    53→    emit_u(0x7ff0000000000001ULL); /* sNaN */
    54→    emit_u(0xfff8000000000000ULL); /* -NaN */
    55→}
    56→
    57→/* 2. Tiny values */
    58→static void test_tiny(void)
    59→{
    60→    emit_u(0x0000000000000001ULL); /* min denorm */
    61→    emit_u(0x8000000000000001ULL);
    62→    emit_u(0x0008000000000000ULL); /* mid denorm */
    63→    emit_u(0x8008000000000000ULL);
    64→    emit_u(0x000fffffffffffffULL); /* max denorm */
    65→    emit_u(0x800fffffffffffffULL);
    66→    emit(DBL_MIN);
    67→    emit(-DBL_MIN);
    68→    emit(1.0e-200);
    69→    emit(-1.0e-200);
    70→}
    71→
    72→/* 3. Known mathematical values */
    73→static void test_known(void)
    74→{
    75→    emit(1.0);
    76→    emit(0.8660254);
    77→    emit(0.7071068);
    78→    emit(0.5);
    79→    emit(0.0);
    80→    emit(-0.5);
    81→    emit(-0.7071068);
    82→    emit(-0.8660254);
    83→    emit(-1.0);
    84→}
    85→
    86→/* 4. Boundary values */
    87→static void test_large(void)
    88→{
    89→    emit_u(0x3ff0000000000001ULL);  /* 1.0 + eps */
    90→    emit_u(0xbff0000000000001ULL);  /* -1.0 - eps */
    91→    emit(2.0);
    92→    emit(-2.0);
    93→    emit(1.5);
    94→    emit(-1.5);
    95→    emit(DBL_MAX);
    96→    emit(-DBL_MAX);
    97→}
    98→
    99→/* 5. Normal range values */
   100→static void test_quadrant(void)
   101→{
   102→    double vals[] = { -0.99, -0.9, -0.5, -0.1, 0.0, 0.1, 0.5, 0.9, 0.99 };
   103→    int n = sizeof(vals) / sizeof(vals[0]);
   104→    for (int i = 0; i < n; i++)
   105→        emit(vals[i]);
   106→}
   107→
   108→/* 6. Hard values near boundaries */
   109→static void test_hard(void)
   110→{
   111→    double cases[] = {
   112→        u2d(0x3fe921fb54442d18ULL), /* 0.7853981... (pi/4 normalized) */
   113→        u2d(0x3ff0000000000000ULL), /* 1.0 */
   114→        u2d(0x3fefffffff600000ULL), /* 1.0 - small epsilon */
   115→        u2d(0xbff0000000000000ULL), /* -1.0 */
   116→        u2d(0xbfefffffff600000ULL), /* -1.0 + small epsilon */
   117→    };
   118→    int n = sizeof(cases) / sizeof(cases[0]);
   119→    for (int i = 0; i < n; i++) {
   120→        emit(cases[i]);
   121→        emit(-cases[i]);
   122→    }
   123→}
   124→
   125→/* 7. Sweep [-1, 1] in 200 steps */
   126→static void test_sweep(void)
   127→{
   128→    int nsteps = 200;
   129→    double step = 2.0 / (double)nsteps;
   130→
   131→    for (int i = 0; i <= nsteps; i++)
   132→        emit(-1.0 + (double)i * step);
   133→}
   134→
   135→/* 8. Sample [0, 0.5] every 4503599627370496 ULP (~50 cases) */
   136→static void test_exhaustive_small(void)
   137→{
   138→    uint64_t end = 0x3fe0000000000000ULL; /* 0.5 */
   139→    for (uint64_t b = 0; b <= end; b += 4503599627370496ULL)
   140→        emit_u(b);
   141→}
   142→
   143→/* ------------------------------------------------------------------ */
   144→
   145→int main(void)
   146→{
   147→    test_special();
   148→    test_tiny();
   149→    test_known();
   150→    test_large();
   151→    test_quadrant();
   152→    test_hard();
   153→    test_sweep();
   154→    test_exhaustive_small();
   155→    return 0;
   156→}
