     1→/*
     2→ * acosf() test harness — prints (input_hex, output_hex) pairs.
     3→ *
     4→ * Build two versions:
     5→ *   1. Linked with optimized Andes assembly acosf  (test_acosf_opt.elf)
     6→ *   2. Linked with toolchain's default acosf        (test_acosf_ref.elf)
     7→ * Run both, diff the output to find discrepancies.
     8→ */
     9→
    10→#include <math.h>
    11→#include <stdint.h>
    12→#include <stdio.h>
    13→#include <float.h>
    14→
    15→static inline uint32_t f2u(float f)
    16→{
    17→    union { float f; uint32_t u; } x;
    18→    x.f = f;
    19→    return x.u;
    20→}
    21→
    22→static inline float u2f(uint32_t u)
    23→{
    24→    union { float f; uint32_t u; } x;
    25→    x.u = u;
    26→    return x.f;
    27→}
    28→
    29→static void emit(float x)
    30→{
    31→    float r = acosf(x);
    32→    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
    33→}
    34→
    35→static void emit_u(uint32_t bits)
    36→{
    37→    emit(u2f(bits));
    38→}
    39→
    40→/* ------------------------------------------------------------------ */
    41→/* Test points                                                         */
    42→/* ------------------------------------------------------------------ */
    43→
    44→/* 1. Special values */
    45→static void test_special(void)
    46→{
    47→    /* Zeros */
    48→    emit(0.0f);
    49→    emit(-0.0f);
    50→
    51→    /* NaN */
    52→    emit_u(0x7fc00000u); /* qNaN */
    53→    emit_u(0x7f800001u); /* sNaN */
    54→    emit_u(0xffc00000u); /* -NaN */
    55→
    56→    /* Infinity (out of domain) */
    57→    emit_u(0x7f800000u); /* +Inf */
    58→    emit_u(0xff800000u); /* -Inf */
    59→}
    60→
    61→/* 2. Tiny values: acos(0) ~ pi/2 */
    62→static void test_tiny(void)
    63→{
    64→    emit_u(0x00000001u); /* min denorm */
    65→    emit_u(0x80000001u);
    66→    emit_u(0x00400000u); /* mid denorm */
    67→    emit_u(0x80400000u);
    68→    emit_u(0x007fffffu); /* max denorm */
    69→    emit_u(0x807fffffu);
    70→    emit(FLT_MIN);
    71→    emit(-FLT_MIN);
    72→    emit(1.0e-20f);
    73→    emit(-1.0e-20f);
    74→    emit(1.0e-10f);
    75→    emit(-1.0e-10f);
    76→}
    77→
    78→/* 3. Known mathematical values */
    79→static void test_known(void)
    80→{
    81→    float pi   = 3.14159265358979323846f;
    82→    float pi_2 = 1.57079632679489661923f;
    83→    float pi_3 = 1.04719755119659774615f;
    84→    float pi_6 = 0.52359877559829887308f;
    85→
    86→    emit(-1.0f);
    87→    emit(-0.999f);
    88→    emit(-0.5f);
    89→    emit(-pi_6);
    90→    emit(0.0f);
    91→    emit(pi_6);
    92→    emit(0.5f);
    93→    emit(0.999f);
    94→    emit(1.0f);
    95→    emit(pi_2);
    96→}
    97→
    98→/* 4. Large arguments (domain boundary) */
    99→static void test_large(void)
   100→{
   101→    float vals[] = {
   102→        1.5f, -1.5f, 2.0f, -2.0f, 10.0f, -10.0f,
   103→        100.0f, -100.0f, FLT_MAX, -FLT_MAX,
   104→    };
   105→    int n = sizeof(vals) / sizeof(vals[0]);
   106→    for (int i = 0; i < n; i++)
   107→        emit(vals[i]);
   108→}
   109→
   110→/* 5. Quadrant transitions (domain boundaries) */
   111→static void test_quadrant(void)
   112→{
   113→    float offsets[] = { -1e-5f, 0.0f, 1e-5f };
   114→    int noff = sizeof(offsets) / sizeof(offsets[0]);
   115→
   116→    float boundaries[] = { -1.0f, 1.0f };
   117→    int nbnd = sizeof(boundaries) / sizeof(boundaries[0]);
   118→
   119→    for (int k = 0; k < nbnd; k++) {
   120→        for (int j = 0; j < noff; j++)
   121→            emit(boundaries[k] + offsets[j]);
   122→    }
   123→}
   124→
   125→/* 6. Hard cases near domain boundaries */
   126→static void test_hard(void)
   127→{
   128→    float cases[] = {
   129→        u2f(0x3f800000u), /* 1.0 */
   130→        u2f(0xbf800000u), /* -1.0 */
   131→        u2f(0x3f7fffffu), /* 1.0 - ULP */
   132→        u2f(0xbf7fffffu), /* -1.0 + ULP */
   133→        0.9999999f, -0.9999999f,
   134→        0.99999999f, -0.99999999f,
   135→    };
   136→    int n = sizeof(cases) / sizeof(cases[0]);
   137→    for (int i = 0; i < n; i++)
   138→        emit(cases[i]);
   139→}
   140→
   141→/* 7. Sweep [-1, 1] in 200 steps */
   142→static void test_sweep(void)
   143→{
   144→    int nsteps = 200;
   145→    for (int i = 0; i <= nsteps; i++)
   146→        emit(-1.0f + 2.0f * (float)i / (float)nsteps);
   147→}
   148→
   149→/* 8. Exhaustive [-1, 1] every 65536 ULP */
   150→static void test_exhaustive_small(void)
   151→{
   152→    uint32_t start = 0xbf800000u; /* -1.0 */
   153→    uint32_t end = 0x3f800000u;   /* 1.0 */
   154→    for (uint32_t b = start; b <= end; b += 65536) {
   155→        if (b >= start && b <= end)
   156→            emit_u(b);
   157→    }
   158→}
   159→
   160→/* ------------------------------------------------------------------ */
   161→
   162→int main(void)
   163→{
   164→    test_special();
   165→    test_tiny();
   166→    test_known();
   167→    test_large();
   168→    test_quadrant();
   169→    test_hard();
   170→    test_sweep();
   171→    test_exhaustive_small();
   172→    return 0;
   173→}
