    42→/* ------------------------------------------------------------------ */
    43→
    44→/* 1. Special values */
    45→static void test_special(void)
    46→{
    47→    /* NaN */
    48→    emit_u(0x7ff8000000000000ULL); /* qNaN */
    49→    emit_u(0x7ff0000000000001ULL); /* sNaN */
    50→    emit_u(0xfff8000000000000ULL); /* -NaN */
    51→
    52→    /* Infinity */
    53→    emit_u(0x7ff0000000000000ULL); /* +Inf (acosh -> +Inf) */
    54→    emit_u(0xfff0000000000000ULL); /* -Inf (domain error) */
    55→}
    56→
    57→/* 2. Tiny values */
    58→static void test_tiny(void)
    59→{
    60→    /* Domain: x >= 1.0 */
    61→    emit_u(0x3ff0000000000000ULL); /* 1.0 exactly */
    62→    emit_u(0x3ff0000000000001ULL); /* 1.0 + eps */
    63→    emit(1.0 + 1.0e-150);
    64→    emit(1.0 + 1.0e-50);
    65→}
    66→
    67→/* 3. Known mathematical values */
    68→static void test_known(void)
    69→{
    70→    /* acosh(1) = 0 */
    71→    emit(1.0);
    72→
    73→    /* acosh(x) = ln(x + sqrt(x^2 - 1)) */
    74→    emit(2.0);     /* acosh(2) = ln(2 + sqrt(3)) ~ 1.317 */
    75→    emit(3.0);     /* acosh(3) = ln(3 + sqrt(8)) ~ 1.763 */
    76→    emit(4.0);     /* acosh(4) = ln(4 + sqrt(15)) ~ 2.063 */
    77→    emit(5.0);     /* acosh(5) = ln(5 + sqrt(24)) ~ 2.292 */
    78→    emit(10.0);    /* acosh(10) ~ 2.993 */
    79→}
