    21→
    22→static inline float u2f(uint32_t u)
    23→{
    24→    union { float f; uint32_t u; } x;
    25→    x.u = u;
    26→    return x.f;
    27→}
    28→
    29→static void emit(float x, float y)
    30→{
    31→    float r = fmodf(x, y);
    32→    printf("%08lx %08lx %08lx\n",
    33→           (unsigned long)f2u(x), (unsigned long)f2u(y), (unsigned long)f2u(r));
    34→}
    35→
    36→static void emit_u(uint32_t x_bits, uint32_t y_bits)
    37→{
    38→    emit(u2f(x_bits), u2f(y_bits));
    39→}
