    41→/* ------------------------------------------------------------------ */
    42→/* Test points                                                         */
    43→/* ------------------------------------------------------------------ */
    44→
    45→/* 1. Special values */
    46→static void test_special(void)
    47→{
    48→    /* Zeros */
    49→    emit(0.0f, 1.0f);
    50→    emit(-0.0f, 1.0f);
    51→    emit(1.0f, 0.0f);  /* fmod(x, 0) = NaN */
    52→
    53→    /* NaN cases */
    54→    emit_u(0x7fc00000u, 1.0f);  /* qNaN as numerator */
    55→    emit(1.0f, u2f(0x7fc00000u));  /* qNaN as denominator */
    56→
    57→    /* Infinity cases */
    58→    emit_u(0x7f800000u, 1.0f);  /* Inf mod 1 = NaN */
    59→    emit_u(0xff800000u, 1.0f);  /* -Inf mod 1 = NaN */
    60→    emit(1.0f, u2f(0x7f800000u));  /* 1 mod Inf = 1 */
    61→}
    62→
    63→/* 2. Tiny values */
    64→static void test_tiny(void)
    65→{
    66→    emit(u2f(0x00000001u), 1.0f);
    67→    emit(u2f(0x80000001u), 1.0f);
    68→    emit(1.0f, FLT_MIN);
    69→    emit(-1.0f, FLT_MIN);
    70→}
    71→
    72→/* 3. Exact divisions (x mod y where y divides x) */
    73→static void test_exact(void)
    74→{
    75→    float vals[] = { 1.0f, 2.0f, 3.0f, 4.0f, 5.0f };
    76→    int n = sizeof(vals) / sizeof(vals[0]);
    77→
    78→    for (int i = 0; i < n; i++) {
    79→        emit(vals[i], vals[i]);       /* x mod x = 0 */
    80→        for (int j = i + 1; j < n; j++) {
    81→            emit(vals[i] * vals[j], vals[j]);  /* (a*b) mod b = 0 */
    82→        }
    83→    }
    84→}
    85→
    86→/* 4. Non-exact divisions */
    87→static void test_remainder(void)
    88→{
    89→    float xs[] = { 0.0f, 1.0f, -1.0f, 5.5f, -5.5f, 100.0f, -100.0f };
    90→    float ys[] = { 0.3f, 1.0f, -1.0f, 2.0f, 3.14159265f };
    91→    int nx = sizeof(xs) / sizeof(xs[0]);
    92→    int ny = sizeof(ys) / sizeof(ys[0]);
    93→
    94→    for (int i = 0; i < nx; i++) {
    95→        for (int j = 0; j < ny; j++) {
    96→            emit(xs[i], ys[j]);
    97→        }
    98→    }
    99→}
   100→
   101→/* 5. Large numerator */
   102→static void test_large_numerator(void)
   103→{
   104→    float divisors[] = { 1.0f, 2.0f, 10.0f, 0.5f };
   105→    int nd = sizeof(divisors) / sizeof(divisors[0]);
   106→
   107→    for (int j = 0; j < nd; j++) {
   108→        emit(1000.0f, divisors[j]);
   109→        emit(-1000.0f, divisors[j]);
   110→        emit(1.0e10f, divisors[j]);
   111→        emit(-1.0e10f, divisors[j]);
   112→        emit(FLT_MAX, divisors[j]);
   113→        emit(-FLT_MAX, divisors[j]);
   114→    }
   115→}
   116→
   117→/* 6. Various divisors */
   118→static void test_divisors(void)
   119→{
   120→    float numerators[] = { 10.0f, 100.0f, -10.0f, -100.0f };
   121→    float divisors[] = { 0.5f, 1.0f, 2.0f, 3.0f, 7.0f, 10.0f, 15.0f };
   122→
   123→    for (int i = 0; i < 4; i++) {
   124→        for (int j = 0; j < 7; j++) {
   125→            emit(numerators[i], divisors[j]);
   126→        }
   127→    }
   128→}
   129→
   130→/* 7. Negative values with sign handling */
   131→static void test_signs(void)
   132→{
   133→    float vals[] = { 1.0f, 2.0f, 3.0f, 5.0f, 10.0f };
   134→    int n = sizeof(vals) / sizeof(vals[0]);
   135→
   136→    for (int i = 0; i < n; i++) {
   137→        for (int j = 0; j < n; j++) {
   138→            emit(vals[i], vals[j]);
   139→            emit(-vals[i], vals[j]);
   140→            emit(vals[i], -vals[j]);
   141→            emit(-vals[i], -vals[j]);
   142→        }
   143→    }
   144→}
   145→
   146→/* 8. Edge cases: small remainder */
   147→static void test_edge_remainder(void)
   148→{
   149→    emit(10.001f, 1.0f);
   150→    emit(10.0001f, 1.0f);
   151→    emit(10.99f, 1.0f);
   152→    emit(10.999f, 1.0f);
   153→    emit(-10.001f, 1.0f);
   154→    emit(-10.0001f, 1.0f);
   155→}
   156→
   157→/* ------------------------------------------------------------------ */
   158→
   159→int main(void)
   160→{
   161→    test_special();
   162→    test_tiny();
   163→    test_exact();
   164→    test_remainder();
   165→    test_large_numerator();
   166→    test_divisors();
   167→    test_signs();
   168→    test_edge_remainder();
   169→    return 0;
   170→}
