    26→    return x.f;
    27→}
    28→
    29→static void emit(float x)
    30→{
    31→    int ex;
    32→    float r = frexpf(x, &ex);
    33→    printf("%08lx %08lx %d\n",
    34→           (unsigned long)f2u(x), (unsigned long)f2u(r), ex);
    35→}
    36→
    37→static void emit_u(uint32_t bits)
    38→{
    39→    emit(u2f(bits));
    40→}
