    67→    emit_u(0x80000001u);
    68→    emit_u(0x00400000u); /* mid denorm */
    69→    emit_u(0x80400000u);
    70→    emit_u(0x007fffffu); /* max denorm */
    71→    emit_u(0x807fffffu);
    72→    emit(FLT_MIN);
    73→    emit(-FLT_MIN);
    74→    emit(1.0e-30f);
    75→    emit(-1.0e-30f);
    76→}
    77→
    78→/* 3. Known values with specific exponents */
    79→static void test_known(void)
    80→{
