    82→        0.5f, -0.5f,      /* exp = 0 */
    83→        1.0f, -1.0f,      /* exp = 1 */
    84→        1.5f, -1.5f,      /* exp = 1 */
    85→        2.0f, -2.0f,      /* exp = 2 */
