    98→        1000.0f, -1000.0f,
    99→        1.0e10f, -1.0e10f,
   100→        1.0e20f, -1.0e20f,
   101→        FLT_MAX, -FLT_MAX,
   102→    };
   103→    int n = sizeof(vals) / sizeof(vals[0]);
   104→    for (int i = 0; i < n; i++)
   105→        emit(vals[i]);
   106→}
   107→
   108→/* 5. Powers of 2 (pure exponent) */
   109→static void test_powers_of_2(void)
   110→{
   111→    for (int i = -10; i <= 10; i++) {
