   113→        emit(v);
   114→        emit(-v);
   115→    }
   116→}
   117→
   118→/* 6. Worst-case mantissa values */
   119→static void test_hard(void)
   120→{
   121→    float cases[] = {
   122→        0.125f, 0.25f, 0.375f, 0.5f, 0.625f, 0.75f, 0.875f, 0.999f,
   123→        1.001f, 1.125f, 1.25f, 1.5f, 1.75f, 1.999f,
