   132→        u2f(0x3f7fffffu), /* just below 1.0 */
   133→        u2f(0x3f000000u), /* 0.5 */
   134→        u2f(0x40000000u), /* 2.0 */
   135→        0.999999940f,      /* near 1.0 */
   136→        1.000000060f,
   137→        4.0f, 16.0f, 64.0f, 256.0f,
   138→    };
   139→    int n = sizeof(cases) / sizeof(cases[0]);
   140→    for (int i = 0; i < n; i++) {
