   151→    float hi = 2.0f;
   152→    int nsteps = 200;
   153→    float step = (hi - lo) / (float)nsteps;
   154→
   155→    for (int i = 0; i <= nsteps; i++)
   156→        emit(lo + (float)i * step);
   157→}
   158→
   159→/* 8. Sample [1, 2] every 4194304 ULP (~250 cases) */
   160→static void test_exhaustive_small(void)
   161→{
   162→    uint32_t start = 0x3f800000u; /* 1.0 */
   163→    uint32_t end   = 0x40000000u; /* 2.0 */
   164→    for (uint32_t b = start; b <= end; b += 4194304)
   165→        emit_u(b);
   166→}
   167→
   168→/* ------------------------------------------------------------------ */
