     9→
    10→#include <math.h>
    11→#include <stdint.h>
    12→#include <stdio.h>
    13→#include <float.h>
    14→
    15→static inline uint32_t f2u(float f)
    16→{
    17→    union { float f; uint32_t u; } x;
    18→    x.f = f;
    19→    return x.u;
    20→}
    21→
    22→static inline float u2f(uint32_t u)
    23→{
    24→    union { float f; uint32_t u; } x;
    25→    x.u = u;
    26→    return x.f;
    27→}
    28→
    29→static void emit(float x)
    30→{
    31→    float ipart;
    32→    float fpart = modff(x, &ipart);
    33→    printf("%08lx %08lx %08lx\n",
    34→           (unsigned long)f2u(x), (unsigned long)f2u(ipart),
    35→           (unsigned long)f2u(fpart));
    36→}
    37→
    38→static void emit_u(uint32_t bits)
    39→{
    40→    emit(u2f(bits));
    41→}
