    43→/* ------------------------------------------------------------------ */
    44→/* Test points                                                         */
    45→/* ------------------------------------------------------------------ */
    46→
    47→/* 1. Special values */
    48→static void test_special(void)
    49→{
    50→    /* Zeros */
    51→    emit(0.0f);
    52→    emit(-0.0f);
    53→
    54→    /* NaN */
    55→    emit_u(0x7fc00000u); /* qNaN */
    56→    emit_u(0x7f800001u); /* sNaN */
    57→    emit_u(0xffc00000u); /* -NaN */
    58→
    59→    /* Infinity */
    60→    emit_u(0x7f800000u); /* +Inf */
    61→    emit_u(0xff800000u); /* -Inf */
    62→}
    63→
    64→/* 2. Tiny values */
    65→static void test_tiny(void)
    66→{
    67→    emit_u(0x00000001u); /* min denorm */
    68→    emit_u(0x80000001u);
    69→    emit_u(0x00400000u); /* mid denorm */
    70→    emit_u(0x80400000u);
    71→    emit_u(0x007fffffu); /* max denorm */
    72→    emit_u(0x807fffffu);
    73→    emit(FLT_MIN);
    74→    emit(-FLT_MIN);
    75→    emit(1.0e-20f);
    76→    emit(-1.0e-20f);
    77→}
    78→
    79→/* 3. Integer and fractional parts */
    80→static void test_known(void)
    81→{
    82→    float vals[] = {
    83→        0.5f, -0.5f,      /* int=0, frac=±0.5 */
    84→        1.5f, -1.5f,      /* int=±1, frac=±0.5 */
    85→        2.7f, -2.7f,      /* int=±2, frac=±0.7 */
    86→        3.14159265f, -3.14159265f,
    87→        10.0f, -10.0f,    /* pure integer */
    88→        10.5f, -10.5f,
    89→        100.3f, -100.3f,
    90→    };
    91→    int n = sizeof(vals) / sizeof(vals[0]);
    92→    for (int i = 0; i < n; i++)
    93→        emit(vals[i]);
    94→}
    95→
    96→/* 4. Large arguments */
    97→static void test_large(void)
    98→{
    99→    float vals[] = {
   100→        1000.0f, -1000.0f,
   101→        1000.5f, -1000.5f,
   102→        1.0e10f, -1.0e10f,
   103→        1.0e20f, -1.0e20f,
   104→        FLT_MAX, -FLT_MAX,
   105→    };
   106→    int n = sizeof(vals) / sizeof(vals[0]);
   107→    for (int i = 0; i < n; i++)
   108→        emit(vals[i]);
   109→}
   110→
   111→/* 5. Pure fractional values (int = 0) */
   112→static void test_fractional(void)
   113→{
   114→    float vals[] = {
   115→        0.1f, -0.1f,
   116→        0.25f, -0.25f,
   117→        0.5f, -0.5f,
   118→        0.75f, -0.75f,
   119→        0.99f, -0.99f,
   120→    };
   121→    int n = sizeof(vals) / sizeof(vals[0]);
   122→    for (int i = 0; i < n; i++)
   123→        emit(vals[i]);
   124→}
   125→
   126→/* 6. Worst-case argument values */
   127→static void test_hard(void)
   128→{
   129→    float cases[] = {
   130→        0.125f, 0.25f, 0.375f, 0.625f, 0.75f, 0.875f, 0.999f,
   131→        1.125f, 2.25f, 3.375f, 4.5f, 5.75f, 9.875f,
   132→    };
   133→    int n = sizeof(cases) / sizeof(cases[0]);
