    10→static inline uint64_t d2u(double d)
    11→{
    12→    union { double d; uint64_t u; } x;
    13→    x.d = d;
    14→    return x.u;
    15→}
    16→
    17→static inline double u2d(uint64_t u)
    18→{
    19→    union { double d; uint64_t u; } x;
    20→    x.u = u;
    21→    return x.d;
    22→}
    23→
    24→static void emit(double x, double y)
    25→{
    26→    double r = nextafter(x, y);
    27→    printf("%016llx %016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(y), (unsigned long long)d2u(r));
    28→}
    29→
    30→static void emit_u(uint64_t x_bits, uint64_t y_bits)
    31→{
    32→    emit(u2d(x_bits), u2d(y_bits));
    33→}
    34→
    35→/* 1. Special values */
    36→static void test_special(void)
    37→{
    38→    emit(0.0, 1.0);
    39→    emit(-0.0, 1.0);
    40→    emit(1.0, 0.0);
    41→    emit(1.0, 1.0);
    42→    emit_u(0x7ff8000000000000ULL, 0x3ff0000000000000ULL);  /* qNaN, 1.0 */
    43→    emit_u(0x7ff0000000000001ULL, 0x3ff0000000000000ULL);  /* sNaN, 1.0 */
    44→    emit_u(0xfff8000000000000ULL, 0x3ff0000000000000ULL);  /* -NaN, 1.0 */
    45→    emit_u(0x3ff0000000000000ULL, 0x7ff8000000000000ULL);  /* 1.0, qNaN */
    46→    emit_u(0x7ff0000000000000ULL, 0x3ff0000000000000ULL);  /* +Inf, 1.0 */
    47→}
    48→
    49→/* 2. Tiny values (denorms and near-zero) */
    50→static void test_tiny(void)
    51→{
    52→    emit_u(0x0000000000000001ULL, 1.0);  /* min denorm toward 1.0 */
    53→    emit_u(0x800fffffffffffffULL, 1.0);  /* mid denorm */
    54→    emit_u(0x000fffffffffffffULL, 1.0);  /* max denorm toward 1.0 */
    55→    emit(DBL_MIN, 1.0);
    56→    emit(-DBL_MIN, 1.0);
    57→    emit(DBL_MIN, 0.0);
    58→    emit(-DBL_MIN, 0.0);
    59→}
    60→
    61→/* 3. Near zero crossing */
    62→static void test_zero_crossing(void)
    63→{
    64→    emit(0.0, 0.5);
    65→    emit(0.0, -0.5);
    66→    emit(-0.0, 0.5);
    67→    emit(-0.0, -0.5);
    68→    emit(0.0, 1.0);
    69→    emit(-0.0, -1.0);
    70→}
    71→
    72→/* 4. Moving away from values */
    73→static void test_away(void)
    74→{
    75→    emit(1.0, 2.0);   /* toward 2.0 */
    76→    emit(1.0, 0.0);   /* toward 0.0 */
    77→    emit(2.0, 1.0);   /* backward */
    78→    emit(-1.0, -2.0); /* toward -2.0 */
    79→    emit(-1.0, 0.0);  /* toward 0.0 */
    80→}
    81→
    82→/* 5. Boundary values */
    83→static void test_boundaries(void)
    84→{
    85→    emit(DBL_MAX, INFINITY);
    86→    emit(DBL_MAX, 0.0);
    87→    emit(-DBL_MAX, -INFINITY);
    88→    emit(-DBL_MAX, 0.0);
