   112→}
   113→
   114→/* 8. Sample across range */
   115→static void test_sweep(void)
   116→{
   117→    double vals[] = { 0.0, 0.5, 1.0, 2.0, 10.0, 100.0 };
   118→    int n = sizeof(vals) / sizeof(vals[0]);
   119→    for (int i = 0; i < n; i++) {
