    41→/* Test points                                                         */
    42→/* ------------------------------------------------------------------ */
    43→
    44→/* 1. Special values */
    45→static void test_special(void)
    46→{
    47→    /* Zeros */
    48→    emit(0.0);
    49→    emit(-0.0);
    50→
    51→    /* NaN */
    52→    emit_u(0x7ff8000000000000ULL); /* qNaN */
    53→    emit_u(0x7ff0000000000001ULL); /* sNaN */
    54→    emit_u(0xfff8000000000000ULL); /* -NaN */
    55→
    56→    /* Infinity */
    57→    emit_u(0x7ff0000000000000ULL); /* +Inf */
    58→    emit_u(0xfff0000000000000ULL); /* -Inf */
    59→}
    60→
    61→/* 2. Tiny values: sqrt(x) ~ sqrt(x) */
    62→static void test_tiny(void)
    63→{
    64→    emit_u(0x0000000000000001ULL); /* min denorm */
    65→    emit_u(0x8000000000000001ULL);
    66→    emit_u(0x0008000000000000ULL); /* mid denorm */
    67→    emit_u(0x8008000000000000ULL);
    68→    emit_u(0x000fffffffffffffULL); /* max denorm */
    69→    emit_u(0x800fffffffffffffULL);
    70→    emit(DBL_MIN);
    71→    emit(-DBL_MIN);
    72→    emit(1.0e-150);
    73→    emit(-1.0e-150);
    74→    emit(1.0e-50);
    75→    emit(-1.0e-50);
    76→}
