    78→/* 3. Known mathematical values (Pythagorean triples) */
    79→static void test_known(void)
    80→{
    81→    /* Perfect squares and Pythagorean relations */
    82→    emit(1.0);   /* sqrt(1) = 1 */
    83→    emit(4.0);   /* sqrt(4) = 2 */
    84→    emit(9.0);   /* sqrt(9) = 3 */
    85→    emit(16.0);  /* sqrt(16) = 4 */
    86→    emit(25.0);  /* sqrt(25) = 5 */
    87→    emit(100.0); /* sqrt(100) = 10 */
    88→
    89→    /* Pythagorean triples: 3-4-5 */
    90→    emit(9.0);   /* 3^2 */
    91→    emit(16.0);  /* 4^2 */
    92→    emit(25.0);  /* 5^2 (sqrt(9+16)) */
    93→
    94→    /* Pythagorean triples: 5-12-13 */
    95→    emit(25.0);  /* 5^2 */
    96→    emit(144.0); /* 12^2 */
    97→    emit(169.0); /* 13^2 (sqrt(25+144)) */
    98→
    99→    /* Irrational values */
   100→    emit(2.0);   /* sqrt(2) */
