   105→/* 4. Large arguments */
   106→static void test_large(void)
   107→{
   108→    double vals[] = {
   109→        1.0e10, 1.0e20, 1.0e100, 1.0e200, 1.0e300,
   110→        -1.0e10, -1.0e20, -1.0e100,
   111→        1000.0, 10000.0, 100000.0,
   112→        -1000.0, -10000.0,
   113→        DBL_MAX, -DBL_MAX,
   114→    };
   115→    int n = sizeof(vals) / sizeof(vals[0]);
   116→    for (int i = 0; i < n; i++)
   117→        emit(vals[i]);
   118→}
   119→
   120→/* 5. Domain boundaries */
   121→static void test_boundary(void)
   122→{
   123→    double step = 0.01;
   124→    /* Values near 0 */
   125→    for (double x = 0.0; x <= 1.0; x += step)
   126→        emit(x);
   127→
   128→    /* Values near perfect squares */
   129→    double bases[] = { 1.0, 10.0, 100.0, 1000.0 };
   130→    int nbases = sizeof(bases) / sizeof(bases[0]);
   131→    for (int i = 0; i < nbases; i++) {
   132→        double base_sq = bases[i] * bases[i];
   133→        emit(base_sq - 0.001);
   134→        emit(base_sq);
   135→        emit(base_sq + 0.001);
   136→    }
   137→}
   138→
   139→/* 6. Worst-case rounding */
   140→static void test_hard(void)
   141→{
   142→    double cases[] = {
   143→        u2d(0x3ff0000000000000ULL), /* 1.0 */
   144→        u2d(0x4000000000000000ULL), /* 2.0 */
   145→        u2d(0x4008000000000000ULL), /* 3.0 */
   146→        u2d(0x4010000000000000ULL), /* 4.0 */
   147→        2.0, 3.0, 5.0, 10.0,
   148→    };
   149→    int n = sizeof(cases) / sizeof(cases[0]);
   150→    for (int i = 0; i < n; i++) {
   151→        emit(cases[i]);
   152→        emit(-cases[i]);
   153→    }
   154→}
   155→
   156→/* 7. Sweep [0, 100] in 200 steps */
   157→static void test_sweep(void)
   158→{
   159→    double hi = 100.0;
   160→    int nsteps = 200;
   161→    double step = hi / (double)nsteps;
   162→
   163→    /* [0, 100] */
   164→    for (int i = 0; i <= nsteps; i++)
   165→        emit((double)i * step);
   166→
   167→    /* Negative values (domain error) */
   168→    for (int i = 1; i <= 20; i++)
   169→        emit(-((double)i * step));
   170→}
   171→
   172→/* 8. Sample [0, 10] every 4194304 ULP (~250 cases) */
   173→static void test_exhaustive_small(void)
   174→{
   175→    uint64_t end = 0x4024000000000000ULL; /* 10.0 */
   176→    for (uint64_t b = 0; b <= end; b += 4194304)
   177→        emit_u(b);
   178→}
